// Реализация стека
class Stack {
  constructor() {
    this.items = [];
  }

  push(item) {
    this.items.push(item); // O(1)
  }

  pop() {
    return this.items.pop(); // O(1)
  }

  peek() {
    return this.items[this.items.length - 1];
  }

  isEmpty() {
    return this.items.length === 0;
  }
}

// Применение: проверка баланса скобок
function isBalanced(str) {
  const stack = [];
  const pairs = { ')': '(', '}': '{', ']': '[' };

  for (let char of str) {
    if ('({['.includes(char)) {
      stack.push(char);
    } else if (')}]'.includes(char)) {
      if (stack.pop() !== pairs[char]) return false;
    }
  }
  return stack.length === 0;
}

isBalanced('({[]})'); // true
isBalanced('({[})');  // false

// Реализация очереди
class Queue {
  constructor() {
    this.items = [];
    this.head = 0; // оптимизация для O(1) dequeue
  }

  enqueue(item) {
    this.items.push(item); // O(1)
  }

  dequeue() {
    if (this.isEmpty()) return undefined;
    const item = this.items[this.head];
    this.head++;
    // Очистка памяти при необходимости
    if (this.head * 2 > this.items.length) {
      this.items = this.items.slice(this.head);
      this.head = 0;
    }
    return item;
  }

  isEmpty() {
    return this.head >= this.items.length;
  }
}

// Применение: BFS (обход дерева в ширину)
function bfs(tree, target) {
  const queue = [tree.root];

  while (queue.length > 0) {
    const node = queue.shift(); // dequeue
    if (node.value === target) return node;
    queue.push(...node.children); // enqueue
  }
  return null;
}

