// Простая реализация хэш-таблицы
class HashTable {
  constructor(size = 53) {
    this.buckets = new Array(size);
  }

  _hash(key) {
    let total = 0;
    for (let char of key) {
      total = (total * 31 + char.charCodeAt(0)) % this.buckets.length;
    }
    return total;
  }

  set(key, value) {
    const index = this._hash(key);
    if (!this.buckets[index]) {
      this.buckets[index] = [];
    }
    // Проверка на существующий ключ
    const pair = this.buckets[index].find(p => p[0] === key);
    if (pair) {
      pair[1] = value;
    } else {
      this.buckets[index].push([key, value]);
    }
  }

  get(key) {
    const index = this._hash(key);
    const bucket = this.buckets[index];
    if (bucket) {
      const pair = bucket.find(p => p[0] === key);
      return pair ? pair[1] : undefined;
    }
    return undefined;
  }
}

// Использование
const ht = new HashTable();
ht.set('name', 'John'); // O(1) average
ht.get('name'); // 'John' - O(1) average

class TreeNode {
  constructor(value) {
    this.value = value;
    this.left = null;
    this.right = null;
  }
}

class BST {
  constructor() {
    this.root = null;
  }

  insert(value) {
    this.root = this._insertNode(this.root, value);
  }

  _insertNode(node, value) {
    if (!node) return new TreeNode(value);
    if (value < node.value) {
      node.left = this._insertNode(node.left, value);
    } else if (value > node.value) {
      node.right = this._insertNode(node.right, value);
    }
    return node;
  }

  search(value) {
    return this._searchNode(this.root, value);
  }

  _searchNode(node, value) {
    if (!node) return null;
    if (value === node.value) return node;
    if (value < node.value) {
      return this._searchNode(node.left, value);
    }
    return this._searchNode(node.right, value);
  }
}

// Сложность:
// Сбалансированное: O(log n)
// Вырожденное (как список): O(n)

function binarySearch(arr, target) {
  let left = 0;
  let right = arr.length - 1;

  while (left <= right) {
    const mid = Math.floor((left + right) / 2);

    if (arr[mid] === target) {
      return mid; // Нашли!
    } else if (arr[mid] < target) {
      left = mid + 1; // Ищем в правой половине
    } else {
      right = mid - 1; // Ищем в левой половине
    }
  }

  return -1; // Не найдено
}

// Пример
const sorted = [1, 3, 5, 7, 9, 11, 13, 15];
binarySearch(sorted, 7); // 3 (индекс)
binarySearch(sorted, 10); // -1

// O(log n) - невероятно быстро!
// 1M элементов = ~20 сравнений

// Факториал: n! = n * (n-1)!
function factorial(n) {
  // Base case
  if (n <= 1) return 1;

  // Recursive case
  return n * factorial(n - 1);
}

// Рекурсия с хвостовой оптимизацией
function factorialTail(n, acc = 1) {
  if (n <= 1) return acc;
  return factorialTail(n - 1, n * acc);
}

// Обход дерева
function traverse(node) {
  if (!node) return;
  console.log(node.value);
  traverse(node.left);
  traverse(node.right);
}

